  const speed = props.tickerSpeed || 5;
  const x = -((frame * speed) % (t1.offsetWidth || 1000));
  if (scroll) scroll.style.transform = `translateX(${x}px)`;

  const ip = ctx.timeline.introProgress;
  const wrap = ctx.root.getElementById('ticker-wrap');
  if (wrap) wrap.style.transform = `translateY(${ctx.utils.lerp(60, 0, ctx.utils.easeOutExpo(ip))}px)`;
