// @dv-prop { "id": "globalOpacity", "type": "slider", "group": "Apariencia", "label": "Opacidad Global", "defaultValue": 100 } 
// @dv-prop { "id": "animCurve", "type": "easing", "group": "Animación", "label": "Curva de Entrada", "defaultValue": "[0.2, 1, 0.3, 1]" }
// @dv-prop { "id": "staggerDelay", "type": "number", "group": "Animación", "label": "Retraso (Offset)", "defaultValue": 0.15 }

window.renderDVGE = (frame, props, ctx) => {
    const intro = ctx.timeline.introProgress;
    const outro = ctx.timeline.outroProgress;
    const opacityMult = (props.globalOpacity ?? 100) / 100;

    const socialConfigs = [
        { id: 'fb', visible: props.showFB, text: props.userFB },
        { id: 'ig', visible: props.showIG, text: props.userIG },
        { id: 'x', visible: props.showX, text: props.userX },
        { id: 'tk', visible: props.showTK, text: props.userTK }
    ];

    const activeSocials = socialConfigs.filter(s => s.visible);

    socialConfigs.forEach((config, index) => {
        const el = ctx.root.getElementById(`item-${config.id}`);
        const textEl = ctx.root.getElementById(`text-${config.id}`);

        if (!el) return;

        if (!config.visible) {
            el.style.display = 'none';
            return;
        }

        el.style.display = 'flex';
        if (textEl) textEl.innerText = config.text;

        const activeIndex = activeSocials.indexOf(config);
        const startOffset = activeIndex * props.staggerDelay;
        const localIntro = ctx.utils.clamp((intro - startOffset) / (1 - startOffset || 1), 0, 1);

        const ease = ctx.utils.bezier(props.animCurve, localIntro);

        const opacity = ctx.utils.lerp(0, 1, ease) * ctx.utils.lerp(1, 0, outro) * opacityMult;
        const xPos = ctx.utils.lerp(-30, 0, ease);
        const lineScale = ctx.utils.lerp(0, 1, ease);

        el.style.opacity = opacity;
        el.style.transform = `translateX(${xPos}px)`;

        const line = el.querySelector('.accent-line');
        if (line) line.style.width = `${lineScale * 100}%`;
    });
};

