// @dv-prop { "id": "globalOpacity", "type": "slider", "group": "Apariencia", "label": "Opacidad Global (%)", "defaultValue": 100 }
// @dv-prop { "id": "typeSpeed", "type": "number", "group": "Animación", "label": "Velocidad Escritura", "defaultValue": 0.4 }
// @dv-prop { "id": "curvaEntrada", "type": "easing", "group": "Animación", "label": "Curva Entrada", "defaultValue": "[0.2, 0.8, 0.2, 1]" }

window.renderDVGE = (frame, props, ctx) => {
  const intro = ctx.timeline.introProgress;
  const outro = ctx.timeline.outroProgress;
  const ease = ctx.utils.bezier(props.curvaEntrada, intro);
  const opacityMultiplier = (props.globalOpacity ?? 100) / 100;

  const windowEl = ctx.root.getElementById('code-window');
  const textEl = ctx.root.getElementById('text-target');
  const cursorEl = ctx.root.getElementById('cursor');
  const headerEl = ctx.root.getElementById('window-header');

  if (windowEl) {
    windowEl.style.border = props.showWindow ? '1px solid rgba(255,255,255,0.1)' : 'none';
    windowEl.style.background = props.showWindow ? '#1e1e1e' : 'transparent';
    windowEl.style.boxShadow = props.showWindow ? '0 30px 60px rgba(0,0,0,0.5)' : 'none';
    if (headerEl) headerEl.style.display = props.showWindow ? 'flex' : 'none';

    const scale = ctx.utils.lerp(0.9, 1, ease) * ctx.utils.lerp(1, 0.95, outro);
    windowEl.style.opacity = ctx.utils.lerp(0, 1, ease) * ctx.utils.lerp(1, 0, outro) * opacityMultiplier;
    windowEl.style.transform = `scale(${scale})`;

    if (textEl) {
      const fullText = props.codeText || "";
      const typeProgress = ctx.utils.clamp((frame - 10) * props.typeSpeed, 0, fullText.length);
      textEl.innerText = fullText.slice(0, Math.floor(typeProgress));
    }

    if (cursorEl) {
      cursorEl.style.opacity = (frame % 30 < 15) ? '1' : '0';
    }
  }
};

