// @dv-prop { "id": "globalOpacity", "type": "slider", "group": "Apariencia", "label": "Opacidad Global (%)", "defaultValue": 100 }
// @dv-prop { "id": "curvaEntrada", "type": "easing", "group": "Animación", "label": "Curva Entrada", "defaultValue": "[0.17, 0.67, 0.83, 0.67]" }
// @dv-prop { "id": "flipFrame", "type": "number", "group": "Animación", "label": "Frame de Giro", "defaultValue": 120 }

window.renderDVGE = (frame, props, ctx) => {
  const intro = ctx.timeline.introProgress;
  const outro = ctx.timeline.outroProgress;
  const ease = ctx.utils.bezier(props.curvaEntrada, intro);
  const opacityMultiplier = (props.globalOpacity ?? 100) / 100;

  const container = ctx.root.getElementById('flashcard-container');
  const card = ctx.root.getElementById('card-inner');
  const textEn = ctx.root.getElementById('text-en');
  const textEs = ctx.root.getElementById('text-es');
  const shadow = ctx.root.getElementById('card-shadow');

  if (container && card) {
    const yPos = ctx.utils.lerp(100, 0, ease) + ctx.utils.lerp(0, -100, outro);
    container.style.opacity = ctx.utils.lerp(0, 1, ease) * ctx.utils.lerp(1, 0, outro) * opacityMultiplier;
    container.style.transform = `translateY(${yPos}px)`;

    const flipStart = props.flipFrame;
    const flipDuration = 40;
    const flipProgress = ctx.utils.clamp((frame - flipStart) / flipDuration, 0, 1);
    const rotationX = ctx.utils.lerp(0, 180, flipProgress);
    card.style.transform = `rotateX(${rotationX}deg)`;

    if (textEn) textEn.innerText = props.englishWord;
    if (textEs) textEs.innerText = props.spanishWord;

    if (shadow) {
        shadow.style.opacity = ctx.utils.lerp(0, 1, ease) * (1 - (flipProgress * 0.5));
        shadow.style.transform = `scale(${ctx.utils.lerp(0.5, 1, ease)})`;
    }
  }
};

/* @dv-prop { "id": "mathColor", "type": "color", "group": "Estilo", "label": "Color Ecuación", "defaultValue": "#ffffff" } */
