// @dv-prop { "id": "globalOpacity", "type": "slider", "group": "Apariencia", "label": "Opacidad Global (%)", "defaultValue": 100 }
// @dv-prop { "id": "curvaEntrada", "type": "easing", "group": "Animación", "label": "Curva Entrada", "defaultValue": "[0.4, 0, 0.2, 1]" }
// @dv-prop { "id": "transFrame", "type": "number", "group": "Transformación", "label": "Frame del Cambio", "defaultValue": 100 }

window.renderDVGE = (frame, props, ctx) => {
  const intro = ctx.timeline.introProgress;
  const outro = ctx.timeline.outroProgress;
  const ease = ctx.utils.bezier(props.curvaEntrada, intro);
  const opacityMultiplier = (props.globalOpacity ?? 100) / 100;

  const container = ctx.root.getElementById('math-container');
  const textEl = ctx.root.getElementById('equation-text');
  const line = ctx.root.getElementById('glow-line');

  if (container && textEl) {
    container.style.opacity = ctx.utils.lerp(0, 1, ease) * ctx.utils.lerp(1, 0, outro) * opacityMultiplier;
    container.style.transform = `scale(${ctx.utils.lerp(0.85, 1, ease)})`;

    const windowSize = 40;
    const startMorph = props.transFrame - (windowSize / 2);
    const progress = ctx.utils.clamp((frame - startMorph) / windowSize, 0, 1);

    textEl.innerText = progress < 0.5 ? props.mathStart : props.mathEnd;

    const distortion = Math.sin(progress * Math.PI);
    textEl.style.filter = `blur(${distortion * 20}px)`;
    textEl.style.letterSpacing = `${distortion * 15}px`;

    if (line) {
      const targetWidth = ctx.utils.lerp(0, 600, ease);
      line.style.width = `${targetWidth}px`;
      line.style.opacity = ctx.utils.lerp(1, 0, distortion);
    }
  }
};

