// @dv-prop { "id": "globalOpacity", "type": "slider", "group": "Apariencia", "label": "Opacidad Global", "defaultValue": 100 }
// @dv-prop { "id": "numBars", "type": "number", "group": "Datos", "label": "Cantidad de Barras", "defaultValue": 5 }
// @dv-prop { "id": "dataCSV", "type": "string", "group": "Datos", "label": "Valores (%)", "defaultValue": "75,90,55,85,40" }
// @dv-prop { "id": "namesCSV", "type": "string", "group": "Datos", "label": "Nombres", "defaultValue": "A,B,C,D,E" }
// @dv-prop { "id": "enableIdle", "type": "boolean", "group": "Animación", "label": "Idle (Movimiento)", "defaultValue": true }
// @dv-prop { "id": "curva", "type": "easing", "group": "Animación", "label": "Curva Entrada", "defaultValue": "[0.2, 0, 0.1, 1]" }

window.renderDVGE = (frame, props, ctx) => {
    const intro = ctx.timeline.introProgress;
    const outro = ctx.timeline.outroProgress;
    const easeMain = ctx.utils.bezier(props.curva, intro);
    const bContainer = ctx.root.getElementById('bars-container');
    const xContainer = ctx.root.getElementById('x-axis');
    const title = ctx.root.getElementById('title');

    if (title) title.innerText = props.mainTitle;
    const values = props.dataCSV.split(',').map(v => parseFloat(v.trim()) || 0);
    const names = props.namesCSV.split(',').map(n => n.trim());

    if (bContainer && bContainer.children.length !== parseInt(props.numBars)) {
        bContainer.innerHTML = ''; xContainer.innerHTML = '';
        for (let i = 0; i < props.numBars; i++) {
            bContainer.innerHTML += `<div class="bar-wrapper"><span id="v-txt-${i}" class="bar-val"></span><div id="v-bar-${i}" class="bar-fill"></div></div>`;
            xContainer.innerHTML += `<div class="x-label"><span>${names[i] || ''}</span></div>`;
        }
    }

    for (let i = 0; i < props.numBars; i++) {
        const bar = ctx.root.getElementById(`v-bar-${i}`);
        const txt = ctx.root.getElementById(`v-txt-${i}`);
        const delay = i * 0.05;
        const bEase = ctx.utils.bezier(props.curva, ctx.utils.clamp((intro - delay) / 0.7, 0, 1));
        const idle = props.enableIdle ? (Math.sin((frame * 0.05) + i) * 1.5) : 0;
        const currentVal = (ctx.utils.lerp(0, values[i] || 0, bEase) + (idle * bEase)) * (1 - outro);

        if (bar) bar.style.height = `${currentVal}%`;
        if (txt) txt.innerText = Math.round(currentVal) + '%';
    }

    const main = ctx.root.getElementById('chart-area');
    if (main) {
        main.style.opacity = easeMain * (1 - outro);
        main.style.transform = `translateY(${ctx.utils.lerp(20, 0, easeMain)}px)`;
    }
};

