// @dv-prop { "id": "data", "type": "string", "group": "Datos", "label": "Valores (%)", "defaultValue": "40,30,15,10,5" }
// @dv-prop { "id": "names", "type": "string", "group": "Datos", "label": "Nombres", "defaultValue": "Ventas,Marketing,Web,Social,Otros" }
// @dv-prop { "id": "c1", "type": "color", "group": "Colores", "label": "Color 1", "defaultValue": "#00f2ff" }
// @dv-prop { "id": "c2", "type": "color", "group": "Colores", "label": "Color 2", "defaultValue": "#7000ff" }
// @dv-prop { "id": "c3", "type": "color", "group": "Colores", "label": "Color 3", "defaultValue": "#ff007a" }
// @dv-prop { "id": "c4", "type": "color", "group": "Colores", "label": "Color 4", "defaultValue": "#ffb800" }
// @dv-prop { "id": "c5", "type": "color", "group": "Colores", "label": "Color 5", "defaultValue": "#00ff85" }

window.renderDVGE = (frame, props, ctx) => {
    const intro = ctx.timeline.introProgress;
    const ease = ctx.utils.bezier([0.2, 0, 0, 1], intro);
    ctx.root.getElementById('main-title').innerText = props.title;
    const vals = props.data.split(',').map(v => parseFloat(v) || 0);
    const names = props.names.split(',').map(n => n.trim());
    const circ = 251.32;
    let acc = 0; let totalAnim = 0;

    for (let i = 0; i < 5; i++) {
        const color = props[`c${i+1}`];
        const val = vals[i] || 0;
        const name = names[i] || "---";
        const seg = ctx.root.getElementById(`s${i+1}`);
        if (seg) {
            const draw = (val / 100) * circ * ease;
            seg.setAttribute('stroke', color);
            seg.setAttribute('stroke-dasharray', `${draw} ${circ}`);
            seg.setAttribute('stroke-dashoffset', -(acc / 100) * circ);
        }
        ctx.root.getElementById(`d${i+1}`).style.background = color;
        ctx.root.getElementById(`n${i+1}`).innerText = name;
        ctx.root.getElementById(`v${i+1}`).innerText = val + "%";
        acc += val; totalAnim += val * ease;
    }
    ctx.root.getElementById('center-val').innerText = Math.round(totalAnim) + "%";
};

