window.renderDVGE = (frame, props, ctx) => {
  const host = ctx.root.getElementById('dv-master-host');
  const svg = ctx.root.querySelector('.ember-mark');
  const wordmark = ctx.root.querySelector('.wordmark');
  const titleEl = ctx.root.getElementById('d-title');
  const subtitleEl = ctx.root.getElementById('d-subtitle');

  if (!svg || !wordmark || !titleEl || !subtitleEl) return;

  const wrapper = ctx.root.getElementById('scene-wrapper');
  if (wrapper) {
    wrapper.style.backgroundColor = props.transparentBg ? 'transparent' : '#050505';
  }

  titleEl.innerText = props.titleText || 'Ember';
  subtitleEl.innerText = props.subtitleText || 'Motion Studio';

  const intro = ctx.utils.clamp(ctx.timeline.introProgress, 0, 1);
  const easeIntro = ctx.utils.easeOutQuart(intro);

  svg.style.opacity = intro.toString();
  svg.style.transform = `translateY(${ctx.utils.lerp(20, 0, easeIntro)}px)`;

  const delayIntro = ctx.utils.clamp((ctx.timeline.introProgress - 0.2) / 0.8, 0, 1);
  const easeDelay = ctx.utils.easeOutQuart(delayIntro);

  wordmark.style.opacity = delayIntro.toString();
  wordmark.style.transform = `translateY(${ctx.utils.lerp(20, 0, easeDelay)}px)`;

  const pulse = Math.sin(frame * 0.05); 
  const normalizedPulse = (pulse + 1) / 2;

  const glow = ctx.utils.lerp(15, 40, normalizedPulse);
  const yOffsetFloat = ctx.utils.lerp(0, -5, normalizedPulse);

  const hexColor = props.emberColor || '#E44C30';
  svg.style.filter = `drop-shadow(0 0 ${glow}px ${hexColor}66)`;
  svg.style.transform += ` translateY(${yOffsetFloat}px)`;
};

