/* @dv-prop { "id": "cardWidth", "type": "number", "group": "Dimensiones", "label": "Ancho Panel", "defaultValue": 350 } */
/* @dv-prop { "id": "accentColor", "type": "color", "group": "Apariencia", "label": "Color Tendencia", "defaultValue": "#00ff88" } */
/* @dv-prop { "id": "panelColor", "type": "color", "group": "Apariencia", "label": "Fondo Panel", "defaultValue": "#121212EE" } */

#scene-wrapper { position: absolute; width: 100%; height: 100%; display: grid; place-items: var(--posicion); padding: 60px; box-sizing: border-box; }
#monitor-card { width: calc(var(--cardWidth) * 1px); background: var(--panelColor); border-left: 4px solid var(--accentColor); padding: 20px; font-family: 'Inter', sans-serif; color: white; overflow: hidden; box-shadow: 0 10px 30px rgba(0,0,0,0.5); border-radius: 4px; }
#header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px; }
#ticker-label { font-size: 14px; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; opacity: 0.8; }
#status-dot { width: 8px; height: 8px; border-radius: 50%; background: var(--accentColor); }
#main-price { font-size: 32px; margin: 0; font-variant-numeric: tabular-nums; font-weight: 800; }
#chart-container { width: 100%; height: 60px; margin-top: 15px; }
#sparkline { width: 100%; height: 100%; }
#chart-path { stroke: var(--accentColor); filter: drop-shadow(0 0 5px var(--accentColor)); }

// @dv-prop { "id": "globalOpacity", "type": "slider", "group": "Apariencia", "label": "Opacidad Global", "defaultValue": 100 }
// @dv-prop { "id": "volatilidad", "type": "number", "group": "Animación", "label": "Ruido Visual", "defaultValue": 5 }

window.renderDVGE = (frame, props, ctx) => {
  const intro = ctx.timeline.introProgress;
  const outro = ctx.timeline.outroProgress;
  const ease = ctx.utils.easeOutQuart(intro);
  const opacityMultiplier = (props.globalOpacity ?? 100) / 100;
  const card = ctx.root.getElementById('monitor-card');
  if (card) {
    card.style.opacity = ease * (1 - outro) * opacityMultiplier;
    card.style.transform = `translateX(${ctx.utils.lerp(50, 0, ease)}px)`;
  }
  const tickerEl = ctx.root.getElementById('ticker-label');
  if (tickerEl) tickerEl.innerText = props.tickerName;
  const priceEl = ctx.root.getElementById('main-price');
  if (priceEl) priceEl.innerText = props.priceValue;
  const path = ctx.root.getElementById('chart-path');
  if (path) {
    const points = 20; const width = 300; const height = 100; let d = '';
    for (let i = 0; i <= points; i++) {
      const x = (i / points) * width;
      const seed = Math.sin(i * 0.5 + frame * 0.05) * props.volatilidad;
      const baseY = 50 + seed;
      const progressLimit = i / points;
      const pointEase = ctx.utils.clamp(ctx.utils.mapRange(ease, progressLimit, progressLimit + 0.2, 0, 1), 0, 1);
      const y = ctx.utils.lerp(height, baseY, pointEase);
      if (i === 0) d += `M ${x} ${y}`; else d += ` L ${x} ${y}`;
    }
    path.setAttribute('d', d);
    path.style.opacity = ctx.utils.lerp(0, 1, ease);
  }
};

/* @dv-prop { "id": "accentColor", "type": "color", "group": "Estilo", "label": "Color de Acento", "defaultValue": "#673AB7" } */
/* @dv-prop { "id": "baseColor", "type": "color", "group": "Estilo", "label": "Color Base", "defaultValue": "#050505" } */

#viewport { position: absolute; width: 1920px; height: 1080px; background: var(--baseColor); overflow: hidden; display: flex; justify-content: center; align-items: center; color: #ffffff; font-family: 'Inter', sans-serif; }
#bg-mesh { position: absolute; width: 150%; height: 150%; background: radial-gradient(circle at center, var(--accentColor) 0%, transparent 70%); filter: blur(80px); opacity: 0.15; }
#main-content { position: relative; z-index: 2; display: flex; flex-direction: column; align-items: center; }
.visual-accent { position: relative; margin-bottom: 60px; }
#orb-glow { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); width: 300px; height: 300px; background: var(--accentColor); border-radius: 50%; filter: blur(100px); }
.product-wrap { width: 240px; height: 240px; border: 1px solid rgba(255,255,255,0.1); border-radius: 40px; background: rgba(255,255,255,0.05); backdrop-filter: blur(10px); display: grid; place-items: center; }
#product-core { width: 80px; height: 80px; background: white; border-radius: 50%; box-shadow: 0 0 40px var(--accentColor); }
#text-stack { text-align: center; }
#hero-text { font-size: 110px; font-weight: 900; letter-spacing: 15px; margin: 0; text-transform: uppercase; }
#line-separator { width: 0px; height: 2px; background: white; margin: 20px auto; }
#sub-text { font-size: 24px; font-weight: 300; letter-spacing: 4px; opacity: 0.7; text-transform: uppercase; }
#overlay-vignette { position: absolute; width: 100%; height: 100%; box-shadow: inset 0 0 300px #000; pointer-events: none; }

// @dv-prop { "id": "globalOpacity", "type": "slider", "group": "Apariencia", "label": "Opacidad Global", "defaultValue": 100 }
// @dv-prop { "id": "motionCurve", "type": "easing", "group": "Animación", "label": "Curva Cinematográfica", "defaultValue": "[0.2, 0, 0, 1]" }
// @dv-prop { "id": "rotationSpeed", "type": "number", "group": "Animación", "label": "Velocidad Órbita", "defaultValue": 0.2 }

window.renderDVGE = (frame, props, ctx) => {
  const intro = ctx.timeline.introProgress;
  const outro = ctx.timeline.outroProgress;
  const ease = ctx.utils.bezier(props.motionCurve, intro);
  const opacityMultiplier = (props.globalOpacity ?? 100) / 100;

  const orb = ctx.root.getElementById('orb-glow');
  const product = ctx.root.getElementById('product-core');
  const heroText = ctx.root.getElementById('hero-text');
  const line = ctx.root.getElementById('line-separator');
  const subText = ctx.root.getElementById('sub-text');
  const bg = ctx.root.getElementById('bg-mesh');

  if (bg) {
    const pulse = Math.sin(frame * 0.02) * 0.05;
    bg.style.opacity = (0.1 + pulse) * (1 - outro) * opacityMultiplier;
    bg.style.transform = `scale(${ctx.utils.lerp(1.2, 1, ease)}) rotate(${frame * 0.05}deg)`;
  }

  if (orb && product) {
    const float = Math.sin(frame * 0.03) * 20;
    const s = ctx.utils.lerp(0.5, 1, ease) * ctx.utils.lerp(1, 0.8, outro);
    orb.style.opacity = ctx.utils.lerp(0, 0.6, ease) * (1 - outro) * opacityMultiplier;
    product.parentElement.style.transform = `translateY(${float}px) scale(${s})`;
    product.parentElement.style.opacity = ease * (1 - outro) * opacityMultiplier;
    product.parentElement.style.rotate = `${frame * props.rotationSpeed}deg`;
  }

  if (heroText) {
    heroText.innerText = props.mainHeadline;
    heroText.style.letterSpacing = `${ctx.utils.lerp(40, 15, ease)}px`;
    heroText.style.opacity = ease * (1 - outro) * opacityMultiplier;
    heroText.style.filter = `blur(${ctx.utils.lerp(20, 0, ease)}px)`;
  }

  if (line) {
    line.style.width = `${ctx.utils.lerp(0, 400, ease)}px`;
    line.style.opacity = ease * (1 - outro) * opacityMultiplier;
  }

  if (subText) {
    subText.innerText = props.subHeadline;
    subText.style.transform = `translateY(${ctx.utils.lerp(20, 0, ease)}px)`;
    subText.style.opacity = ctx.utils.clamp(ctx.utils.mapRange(intro, 0.5, 1, 0, 0.7), 0, 0.7) * (1 - outro) * opacityMultiplier;
  }
};
